import React, { useEffect, useRef, useState } from "react";

function BrandHighlights() {
  const brands = [
    { id: 1, name: "Lakme", image: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSjX-Z2NPO0zrh59FBiBe1muoUGeRWP3Uq0NA&s" },
    { id: 2, name: "Maybelline", image: "data:image/jpeg;base64," },
    { id: 3, name: "Mamaearth", image: "data:image/jpeg;base64," },
    { id: 4, name: "Nivea", image: "data:image/jpeg;base64," },
    { id: 5, name: "Revlon", image: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQFzxILt1fjMwD25ORVfussSFqe7Rlco38NSw&s" },
    { id: 6, name: "L'Oreal", image: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSwJJee-vSEpELAH_zamb4_db0uanW-8GVbEQ&s" },
    { id: 7, name: "The Body Shop", image: "data:image/jpeg;base64," },
    { id: 8, name: "Nykaa", image: "data:image/jpeg;base64," },
    { id: 9, name: "Himalaya", image: "data:image/jpeg;base64," },
    { id: 10, name: "Forest Essentials", image: "data:image/jpeg;base64," },
    { id: 11, name: "Garnier", image: "data:image/jpeg;base64," },
    { id: 12, name: "Clinique", image: "data:image/jpeg;base64," },
  ];

  const scrollRef = useRef(null);
  const [centerIndex, setCenterIndex] = useState(0);

  useEffect(() => {
    const scrollContainer = scrollRef.current;
    let speed = 1;
    let animationFrame;

    const scrollStep = () => {
      if (scrollContainer) {
        scrollContainer.scrollLeft += speed;

        if (scrollContainer.scrollLeft >= scrollContainer.scrollWidth / 2) {
          scrollContainer.scrollLeft = 0;
        }

        const children = scrollContainer.children;
        const containerCenter = scrollContainer.scrollLeft + scrollContainer.clientWidth / 2;
        let closestIndex = 0;
        let closestDistance = Infinity;

        for (let i = 0; i < children.length; i++) {
          const childCenter = children[i].offsetLeft + children[i].offsetWidth / 2;
          const distance = Math.abs(containerCenter - childCenter);
          if (distance < closestDistance) {
            closestDistance = distance;
            closestIndex = i;
          }
        }
        setCenterIndex(closestIndex);

        animationFrame = requestAnimationFrame(scrollStep);
      }
    };

    animationFrame = requestAnimationFrame(scrollStep);
    return () => cancelAnimationFrame(animationFrame);
  }, []);

  return (
    <section
      style={{
        padding: "40px 5%",
        background: "linear-gradient(120deg, #fef9f4, #fff5f8)",
      }}
    >
      {/* Heading */}
      <div style={{ marginBottom: "35px" }}>
        <h2
          style={{
            textAlign: "center",
            fontSize: "28px",
            fontWeight: "700",
            margin: "0 0 8px 0",
            color: "#d63384",
          }}
        >
          Popular Beauty Brands
        </h2>
        <p
          style={{
            textAlign: "center",
            color: "#555",
            fontSize: "14px",
            margin: "0",
          }}
        >
          Discover top beauty brands trusted worldwide
        </p>
      </div>

      {/* Brand carousel */}
      <div
        ref={scrollRef}
        style={{
          display: "flex",
          gap: "12px",
          overflowX: "hidden",
          scrollBehavior: "smooth",
          paddingBottom: "15px",
        }}
      >
        {[...brands, ...brands].map((brand, index) => {
          const isCenter = index === centerIndex;
          return (
            <div
              key={index}
              style={{
                minWidth: "120px", // smaller card
                height: "180px", // smaller height
                borderRadius: "12px",
                overflow: "hidden",
                boxShadow: isCenter
                  ? "0 10px 25px rgba(0,0,0,0.2)"
                  : "0 5px 15px rgba(0,0,0,0.1)",
                transition: "all 0.3s ease",
                transform: isCenter ? "scale(1.1)" : "scale(1)",
                flexShrink: 0,
                cursor: "pointer",
                position: "relative",
                backgroundColor: "#fff",
              }}
            >
              {brand.image ? (
                <img
                  src={brand.image}
                  alt={brand.name}
                  style={{
                    width: "100%",
                    height: "100%",
                    objectFit: "contain", // keeps logo proportions
                    padding: "10px", // small padding inside card
                    backgroundColor: "#fff",
                  }}
                />
              ) : (
                <div
                  style={{
                    width: "100%",
                    height: "100%",
                    display: "flex",
                    justifyContent: "center",
                    alignItems: "center",
                    backgroundColor: "#ffe4e1",
                    fontWeight: "600",
                    color: "#d63384",
                    fontSize: "14px",
                    padding: "5px",
                    textAlign: "center",
                  }}
                >
                  {brand.name}
                </div>
              )}

              {/* Brand name overlay */}
              <div
                style={{
                  position: "absolute",
                  bottom: "0",
                  width: "100%",
                  padding: "4px 0",
                  background: "linear-gradient(0deg, rgba(0,0,0,0.5), rgba(0,0,0,0))",
                  color: "#fff",
                  fontWeight: "600",
                  textAlign: "center",
                  fontSize: "13px",
                }}
              >
                {brand.name}
              </div>
            </div>
          );
        })}
      </div>
    </section>
  );
}

export default BrandHighlights;